#include <string>
#include <vector>
#include <unordered_map>

using namespace std;

long long solve(string s) {
    // Count occurrences of each character
    unordered_map<char, int> count;
    for (char c : s) {
        count[c]++;
    }

    // Precompute the number of 'C's and 'T's after each position
    vector<int> c_after(s.size() + 1, 0);
    vector<int> t_after(s.size() + 1, 0);

    // Fill c_after and t_after from the end
    for (int i = s.size() - 1; i >= 0; --i) {
        c_after[i] = c_after[i + 1] + count['C'];
        t_after[i] = t_after[i + 1] + count['T'];
    }

    // Precompute the number of 'L's before each position
    vector<int> l_before(s.size() + 1, 0);
    for (int i = 0; i < s.size(); ++i) {
        l_before[i + 1] = l_before[i] + count['L'];
    }

    long long max_count = 0;

    // Try inserting 'L' at each position
    for (int i = 0; i <= s.size(); ++i) {
        int l_before_insert = l_before[i];
        int c_after_insert = c_after[i + 1];
        int t_after_insert = t_after[i + 1];
        long long total = static_cast<long long>(l_before_insert) * c_after_insert * t_after_insert;
        max_count = max(max_count, total);
    }

    // Try inserting 'C' at each position
    for (int i = 0; i <= s.size(); ++i) {
        int l_before_insert = l_before[i];
        int c_before_insert = count['C'] - c_after[i + 1];
        int t_after_insert = t_after[i + 1];
        long long total = static_cast<long long>(l_before_insert) * c_before_insert * t_after_insert;
        max_count = max(max_count, total);
    }

    // Try inserting 'T' at each position
    for (int i = 0; i <= s.size(); ++i) {
        int l_before_insert = l_before[i];
        int c_after_insert = c_after[i + 1];
        int t_before_insert = count['T'] - t_after[i + 1];
        long long total = static_cast<long long>(l_before_insert) * c_after_insert * t_before_insert;
        max_count = max(max_count, total);
    }

    return max_count;
}
